\boxed{\textbf{A universal two-term Egyptian-fraction split.}\;\; \text{For any integer }n\ge 2,\text{ use the identity}
\[
\frac{1}{n}=\frac{1}{n+1}+\frac{1}{n(n+1)}.
\]
\text{Proof: }
\frac{1}{n+1}+\frac{1}{n(n+1)}=\frac{n}{n(n+1)}+\frac{1}{n(n+1)}=\frac{n+1}{n(n+1)}=\frac{1}{n}.
\]

\textbf{Decomposing into more unit fractions.}\;\; \text{Since the second term is itself a unit fraction, you can repeat the same step on it:}
\[
\frac{1}{n(n+1)}=\frac{1}{n(n+1)+1}+\frac{1}{n(n+1)\bigl(n(n+1)+1\bigr)},
\]
\text{and continue inductively. This shows any unit fraction } \frac1n \text{ can be written as a sum of two (or arbitrarily many) other unit fractions.}}

